"use client";

import { Dispatch, SetStateAction, useRef, useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import {
  Dropzone,
  DropzoneEmptyState,
  DropzoneContent,
} from "@/components/ui/shadcn-io/dropzone";
import { FileText, Image, Sparkles, Download, Loader2, ChevronDown, ChevronUp } from "lucide-react";

// Previous output block component
function PreviousOutput({ content, type }: { content: string; type: string }) {
  const [isOpen, setIsOpen] = useState(false);
  
  return (
    <div className="border border-slate-200 rounded-lg overflow-hidden bg-slate-50">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full px-4 py-3 flex items-center justify-between hover:bg-slate-100 transition-colors"
      >
        <span className="text-sm font-medium text-slate-700">
          Previous {type === 'code' ? 'Code Execution' : 'Output'}
        </span>
        {isOpen ? (
          <ChevronUp className="w-4 h-4 text-slate-500" />
        ) : (
          <ChevronDown className="w-4 h-4 text-slate-500" />
        )}
      </button>
      {isOpen && (
        <div className="px-4 py-3 border-t border-slate-200 bg-white">
          <pre className="text-xs text-slate-600 whitespace-pre-wrap font-mono">
            {content}
          </pre>
        </div>
      )}
    </div>
  );
}

// Animated thinking indicator
function ThinkingIndicator() {
  const [dots, setDots] = useState('');
  
  useEffect(() => {
    const interval = setInterval(() => {
      setDots(prev => prev.length >= 3 ? '' : prev + '.');
    }, 500);
    return () => clearInterval(interval);
  }, []);
  
  return (
    <div className="flex items-center gap-3 text-slate-500 py-4">
      <div className="flex gap-1">
        <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
        <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
        <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
      </div>
      <span className="text-sm">Processing{dots}</span>
    </div>
  );
}

// Pulse animation for active content
function PulseBackground() {
  return (
    <div className="absolute inset-0 -z-10">
      <div className="absolute inset-0 bg-gradient-to-r from-blue-50 via-indigo-50 to-blue-50 animate-pulse" 
           style={{ animationDuration: '3s' }} />
    </div>
  );
}

export default function Home() {
  const [contextFiles, setContextFiles] = useState<File[]>([]);
  const [templateFile, setTemplateFile] = useState<File | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isStreaming, setIsStreaming] = useState(false);

  // Current active outputs
  const [currentText, setCurrentText] = useState("");
  const [currentCode, setCurrentCode] = useState("");
  
  // Previous outputs (moved to accordion)
  const [previousOutputs, setPreviousOutputs] = useState<Array<{ content: string; type: 'text' | 'code' }>>([]);
  
  const [downloadPath, setDownloadPath] = useState<string | null>(null);
  const esRef = useRef<EventSource | null>(null);
  const outputEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom
  useEffect(() => {
    outputEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentText, currentCode]);

  const startStream = async () => {
    if (!templateFile) {
      setError("Please upload a template file.");
      return;
    }

    setError(null);
    setIsStreaming(true);
    setCurrentText("");
    setCurrentCode("");
    setPreviousOutputs([]);
    setDownloadPath(null);

    try {
      const form = new FormData();
      contextFiles.forEach((f) => form.append("contextFiles", f));
      form.append("templateFiles", templateFile);

      const res = await fetch("/api/upload", { method: "POST", body: form });

      if (!res.ok) {
        setError("Upload failed.");
        setIsStreaming(false);
        return;
      }

      const { jobId } = await res.json();

      const es = new EventSource(`/api/stream/${jobId}`);
      esRef.current = es;

      es.onopen = () => {
        console.log("EventSource connection opened");
      };

      es.onerror = (e) => {
        console.error("EventSource error:", e);
        if (es.readyState === EventSource.CLOSED && !downloadPath) {
          setError("Connection interrupted. The generation may have failed.");
          setIsStreaming(false);
        }
      };

      // TEXT DELTAS - append to current text
      es.addEventListener("response.output_text.delta", (e: MessageEvent) => {
        const data = e.data;
        setCurrentText((prev) => prev + data);
      });

      // TEXT DONE - move current text to previous, clear current
      es.addEventListener("response.output_text.done", (e: MessageEvent) => {
        const finalText = e.data;
        setCurrentText((prev) => {
          const fullText = prev + finalText;
          if (fullText.trim()) {
            setPreviousOutputs((prevOutputs) => [...prevOutputs, { content: fullText, type: 'text' }]);
          }
          return ""; // Clear current
        });
      });

      // CODE INTERPRETER - move current code to previous if exists, then set new code
      es.addEventListener("response.code_interpreter_call_code.done", (e: MessageEvent) => {
        const text = e.data.replace(/\\n/g, "\n");
        
        // Move current code to previous if it exists
        setCurrentCode((prev) => {
          if (prev.trim()) {
            setPreviousOutputs((prevOutputs) => [...prevOutputs, { content: prev, type: 'code' }]);
          }
          return text; // Set new code as current
        });
      });

      // COMPLETED
      es.addEventListener("completed", (e: MessageEvent) => {
        console.log("Completed event received:", e.data);
        
        // Move any remaining current outputs to previous
        setCurrentText((prev) => {
          if (prev.trim()) {
            setPreviousOutputs((prevOutputs) => [...prevOutputs, { content: prev, type: 'text' }]);
          }
          return "";
        });
        setCurrentCode((prev) => {
          if (prev.trim()) {
            setPreviousOutputs((prevOutputs) => [...prevOutputs, { content: prev, type: 'code' }]);
          }
          return "";
        });
        
        setDownloadPath(e.data);
        es.close();
        setIsStreaming(false);
      });

      // ERROR event
      es.addEventListener("error", (e: MessageEvent) => {
        console.error("Server error event:", e.data);
        setError(`Server error: ${e.data}`);
        setIsStreaming(false);
        es.close();
      });

    } catch (err) {
      console.error("Stream initialization error:", err);
      setError("Failed to start generation. Please try again.");
      setIsStreaming(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50">
      {/* Header */}
      <div className="bg-white/80 backdrop-blur-sm border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-6 py-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-lg flex items-center justify-center">
              <Sparkles className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-2xl font-bold text-slate-900">
              Document Generator
            </h1>
          </div>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-6 py-12">
        {/* Instructions Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 mb-8">
          <h2 className="text-lg font-semibold text-slate-900 mb-3">
            How it works
          </h2>
          <div className="flex flex-col md:flex-row gap-6 text-sm text-slate-600">
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                1
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">Add context</div>
                Upload images or documents for reference
              </div>
            </div>
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                2
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">Choose template</div>
                Upload your document template
              </div>
            </div>
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                3
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">Generate</div>
                Let AI create your document
              </div>
            </div>
          </div>
        </div>

        {/* Upload Section */}
        <div className="grid md:grid-cols-2 gap-6 mb-8">
          {/* Context Files */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4">
              <Image className="w-5 h-5 text-slate-600" />
              <h3 className="text-lg font-semibold text-slate-900">
                Context Files
              </h3>
              <span className="text-xs text-slate-500 ml-auto">
                Optional
              </span>
            </div>
            <Dropzone
              maxFiles={100}
              onDrop={setContextFiles}
              src={contextFiles}
              className="border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50/50 transition-all rounded-xl bg-slate-50/50"
            >
              <DropzoneEmptyState />
              <DropzoneContent />
            </Dropzone>
            {contextFiles.length > 0 && (
              <p className="text-sm text-slate-600 mt-3">
                {contextFiles.length} file{contextFiles.length !== 1 ? 's' : ''} added
              </p>
            )}
          </div>

          {/* Template File */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4">
              <FileText className="w-5 h-5 text-slate-600" />
              <h3 className="text-lg font-semibold text-slate-900">
                Template File
              </h3>
              <span className="text-xs text-red-500 ml-auto">
                Required
              </span>
            </div>
            <Dropzone
              maxFiles={1}
              onDrop={(files) => setTemplateFile(files[0] || null)}
              src={templateFile ? [templateFile] : []}
              className="border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50/50 transition-all rounded-xl bg-slate-50/50"
            >
              <DropzoneEmptyState />
              <DropzoneContent />
            </Dropzone>
            {templateFile && (
              <p className="text-sm text-slate-600 mt-3">
                {templateFile.name}
              </p>
            )}
          </div>
        </div>

        {/* Error Display */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-xl p-4 mb-6">
            <p className="text-sm text-red-800">{error}</p>
          </div>
        )}

        {/* Generate Button */}
        <div className="flex justify-center mb-8">
          <Button
            onClick={startStream}
            disabled={!templateFile || isStreaming}
            size="lg"
            className="bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white px-8 py-6 text-lg rounded-xl shadow-lg hover:shadow-xl transition-all disabled:opacity-50"
          >
            {isStreaming ? (
              <>
                <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                Generating...
              </>
            ) : (
              <>
                <Sparkles className="w-5 h-5 mr-2" />
                Generate Document
              </>
            )}
          </Button>
        </div>

        {/* Output Section */}
        {(isStreaming || previousOutputs.length > 0 || downloadPath) && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center gap-2">
              <Sparkles className="w-5 h-5 text-blue-600" />
              Generation Progress
            </h3>

            <div className="space-y-4">
              {/* Previous outputs in accordions */}
              {previousOutputs.map((output, idx) => (
                <PreviousOutput
                  key={idx}
                  content={output.content}
                  type={output.type}
                />
              ))}

              {/* Current Code Output (takes priority at top) */}
              {currentCode && (
                <div className="relative border-2 border-blue-300 rounded-lg p-4 bg-gradient-to-br from-blue-50 to-indigo-50">
                  <PulseBackground />
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse" />
                    <span className="text-sm font-semibold text-blue-900">Code Execution</span>
                  </div>
                  <pre className="text-sm text-slate-700 whitespace-pre-wrap font-mono">
                    {currentCode}
                  </pre>
                </div>
              )}

              {/* Current Text Output */}
              {currentText && (
                <div className="relative border-2 border-green-300 rounded-lg p-4 bg-gradient-to-br from-green-50 to-emerald-50">
                  <PulseBackground />
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
                    <span className="text-sm font-semibold text-green-900">Response</span>
                  </div>
                  <div className="text-sm text-slate-700 whitespace-pre-wrap">
                    {currentText}
                  </div>
                </div>
              )}

              {/* Thinking indicator when streaming but no current output */}
              {isStreaming && !currentText && !currentCode && (
                <ThinkingIndicator />
              )}

              {/* Download Button */}
              {downloadPath && (
                <div className="pt-4 border-t border-slate-200">
                  <a
                    href={downloadPath}
                    download
                    className="inline-flex items-center gap-2 bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 text-white px-6 py-3 rounded-lg shadow-md hover:shadow-lg transition-all"
                  >
                    <Download className="w-5 h-5" />
                    Download Completed Document
                  </a>
                </div>
              )}

              <div ref={outputEndRef} />
            </div>
          </div>
        )}
      </div>
    </div>
  );
}